// Extrai informações do erro do Flare
const error = items[0].json;

const errorData = {
  exception: error.exception?.class || 'Unknown',
  message: error.exception?.message || 'No message',
  file: error.exception?.file || '',
  line: error.exception?.line || 0,
  trace: error.exception?.trace?.slice(0, 5) || [],
  context: error.context || {},
  environment: error.context?.env || 'production',
  timestamp: new Date().toISOString(),
  url: error.request?.url || '',
  method: error.request?.method || '',
  tenant_id: error.context?.tenant_id || null,
  tenant_name: error.context?.tenant_name || null
};

return {
  json: {
    error: errorData,
    prompt: `ERRO DE PRODUÇÃO NO YUMGO:

Exceção: ${errorData.exception}
Mensagem: ${errorData.message}
Arquivo: ${errorData.file}:${errorData.line}
URL: ${errorData.url}
Tenant: ${errorData.tenant_name || 'Central'}

Stack Trace:
${errorData.trace.map((t, i) => `${i+1}. ${t.class}@${t.method} (${t.file}:${t.line})`).join('\n')}

ANALISE:
1. Identifique a causa raiz
2. Sugira a correção necessária
3. Forneça o código corrigido se possível
4. Indique se é crítico ou pode esperar

Resposta em formato JSON:
{
  "severity": "critical|high|medium|low",
  "cause": "descrição da causa",
  "solution": "descrição da solução",
  "code_fix": "código corrigido (se aplicável)",
  "file_path": "caminho do arquivo a corrigir",
  "can_auto_fix": true|false
}`
  }
};

// Parse resposta do Claude
const claudeResponse = items[0].json.content[0].text;

// Tenta extrair JSON da resposta
let analysis;
try {
  // Remove markdown code blocks se houver
  const jsonMatch = claudeResponse.match(/```json\s*([\s\S]*?)```/) || 
                    claudeResponse.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  } else {
    analysis = JSON.parse(claudeResponse);
  }
} catch (e) {
  // Se falhar, cria estrutura básica
  analysis = {
    severity: 'medium',
    cause: 'Não foi possível parsear resposta do Claude',
    solution: claudeResponse,
    can_auto_fix: false
  };
}

// Adiciona dados do erro original
analysis.original_error = items[0].json.error;

return {
  json: analysis
};

// Validação de segurança antes de aplicar auto-fix
const analysis = items[0].json;

// Lista de arquivos BLOQUEADOS para auto-fix
const BLOCKED_FILES = [
  '.env',
  'composer.json',
  'composer.lock',
  'package.json',
  'database/migrations/',
  'config/database.php',
  'app/Providers/AppServiceProvider.php',
  'app/Providers/TenancyServiceProvider.php'
];

// Lista de padrões PERIGOSOS no código
const DANGEROUS_PATTERNS = [
  /DB::raw\(/i,
  /DB::statement\(/i,
  /\$_GET|\$_POST|\$_REQUEST/,
  /exec\(|system\(|shell_exec\(/,
  /eval\(/,
  /DROP TABLE|TRUNCATE|DELETE FROM.*WHERE 1=1/i,
  /->whereRaw\(/,
  /payment_status|cashback_balance|asaas_/i  // Campos financeiros
];

// Verifica se arquivo está bloqueado
const isBlockedFile = BLOCKED_FILES.some(blocked => 
  analysis.file_path?.includes(blocked)
);

// Verifica se código contém padrões perigosos
const hasDangerousPattern = analysis.code_fix 
  ? DANGEROUS_PATTERNS.some(pattern => pattern.test(analysis.code_fix))
  : false;

// Verifica impacto de segurança
const hasSecurityImpact = analysis.security_impact && 
  ['médio', 'alto', 'medium', 'high'].includes(analysis.security_impact.toLowerCase());

// DECISÃO FINAL
let canAutoFix = analysis.can_auto_fix === true;
let blockReason = null;

if (isBlockedFile) {
  canAutoFix = false;
  blockReason = 'Arquivo está na lista de bloqueio (crítico para o sistema)';
}

if (hasDangerousPattern) {
  canAutoFix = false;
  blockReason = 'Código contém padrões perigosos (raw SQL, exec, dados financeiros)';
}

if (hasSecurityImpact) {
  canAutoFix = false;
  blockReason = 'Impacto de segurança médio/alto - requer revisão manual';
}

// Se severity for 'low', só aplica se Claude marcou explicitamente can_auto_fix=true
if (analysis.severity === 'low' && !analysis.can_auto_fix) {
  canAutoFix = false;
  blockReason = 'Severidade baixa sem aprovação explícita do Claude';
}

return {
  json: {
    ...analysis,
    validated_auto_fix: canAutoFix,
    block_reason: blockReason,
    security_check: {
      blocked_file: isBlockedFile,
      dangerous_pattern: hasDangerousPattern,
      security_impact: hasSecurityImpact
    }
  }
};

