    message: `fix: ${fix.cause.substring(0, 72)}\n\n${fix.solution}\n\nAuto-fixed by Claude AI via n8n workflow\nSeverity: ${fix.severity}\n\nCo-Authored-By: Claude Sonnet 4.5 <noreply@anthropic.com>`,
